#!/usr/bin/env bash
# Write SHINE agent YAML with paths from server_env.sh
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
# shellcheck source=/dev/null
source "${SCRIPT_DIR}/source_server_env.sh"

OUT="${SHINE_AGENT_CONFIG:-${MAB_ROOT}/configs/agent_conf/SHINE_Agents/SHINE_agent_server.yaml}"
mkdir -p "$(dirname "${OUT}")"

cat > "${OUT}" <<EOF
# Auto-generated by generate_server_agent_config.sh — edit server_env.sh to change paths.
agent_name: SHINE_agent_server
model: shine-qwen3-8b
temperature: 0.4
top_p: 0.9
top_k: 10
output_dir: ./outputs/shine-qwen3-8b-server

shine_root: ${SHINE_ROOT}
shine_cfg_path: configs/Qwen3-8B-MAB.yaml

base_model_path: ${BASE_MODEL}
shine_model_root: ${SHINE_MODEL_ROOT}

use_mab_context_max_length: true
use_mab_conversation_max_length: true
shine_conversation_max_length: 4096
use_mab_generation_max_length: true

device: cuda
EOF

echo "Wrote ${OUT}"
